#include <iostream>
#include <string>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string table;
    cin >> table;

    char table_rank = table[0];
    char table_suit = table[1];

    bool lucky = false;
    for (int i = 0; i < 5; ++i) {
        string card;
        cin >> card;
        if (card[0] == table_rank || card[1] == table_suit) {
            lucky = true;
        }
    }

    cout << (lucky ? "YES" : "NO") << "\n";

    return 0;
}
